mapper.select:
SELECT 0 AS STR_SEQ,
       r.SSPS_DL_CRT_DT, r.SSPS_DL_ID, r.RPR_RSN_CNTNT,
       r.REG_ID, r.REG_DT, r.UPD_ID, r.UPD_DT,
       c.DL_P_RNMCNO, c.RPR_PRGRS_CCD, c.INST_ID,
       a.DL_AMT
FROM NIC67B r
JOIN NIC66B c ON c.SSPS_DL_CRT_DT = r.SSPS_DL_CRT_DT AND c.SSPS_DL_ID = r.SSPS_DL_ID
LEFT JOIN (
    SELECT SSPS_DL_CRT_DT, SSPS_DL_ID, SUM(DL_AMT) AS DL_AMT
    FROM NIC75B GROUP BY SSPS_DL_CRT_DT, SSPS_DL_ID
) a ON a.SSPS_DL_CRT_DT = r.SSPS_DL_CRT_DT AND a.SSPS_DL_ID = r.SSPS_DL_ID
WHERE c.SSPS_DL_CRT_CCD = 'STR'

    AND c.RPR_PRGRS_CCD = #{strStCd}


    AND c.DL_P_RNMCNO = #{custNo}


    AND r.SSPS_DL_ID = #{caseId}


    AND r.SSPS_DL_CRT_DT >= #{strDtFrom}


    AND r.SSPS_DL_CRT_DT <= #{strDtTo}

ORDER BY r.REG_DT DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM NIC67B r
JOIN NIC66B c ON c.SSPS_DL_CRT_DT = r.SSPS_DL_CRT_DT AND c.SSPS_DL_ID = r.SSPS_DL_ID
WHERE c.SSPS_DL_CRT_CCD = 'STR'

    AND c.RPR_PRGRS_CCD = #{strStCd}


    AND c.DL_P_RNMCNO = #{custNo}


    AND r.SSPS_DL_ID = #{caseId}


    AND r.SSPS_DL_CRT_DT >= #{strDtFrom}


    AND r.SSPS_DL_CRT_DT <= #{strDtTo}

mapper.insert:
INSERT INTO NIC67B (
    SSPS_DL_CRT_DT, SSPS_DL_ID, RPR_RSN_CNTNT, REG_ID, REG_DT
) VALUES (
    #{strDt}, #{strNo}, #{suspRsn}, #{regId}, CURRENT_TIMESTAMP
)
